"><div class=\"rbs-img  category10798 \"><div class=\"rbs-img-image   rbs-lightbox \"><div class=\"rbs-img-thumbs\" data-thumbnail=\"https://familylifecrc.org/wp-content/uploads/2023/01/cssj-300x217.jpg\" title=\"cssj\" data-width=\"300\" data-height=\"217\"></div><div class=\"rbs-img-data-popup\" data-popup=\"https://familylifecrc.org/wp-content/uploads/2023/01/cssj.jpg\" title=\"\"></div><div class=\"thumbnail-overlay\"><div class=\"rbsIcons\"><i class=\"fa fa-search-plus rbsZoomIcon \"></i></div></div></div></div><div class=\"rbs-img  category10798 \"><div class=\"rbs-img-image   rbs-lightbox \"><div class=\"rbs-img-thumbs\" data-thumbnail=\"https://familylifecrc.org/wp-content/uploads/2023/01/cssj2-300x217.jpg\" title=\"cssj2\" data-width=\"300\" data-height=\"217\"></div><div class=\"rbs-img-data-popup\" data-popup=\"https://familylifecrc.org/wp-content/uploads/2023/01/cssj2.jpg\" title=\"\"></div><div class=\"thumbnail-overlay\"><div class=\"rbsIcons\"><i class=\"fa fa-search-plus rbsZoomIcon \"></i></div></div></div></div><div class=\"rbs-img  category10798 \"><div class=\"rbs-img-image   rbs-lightbox \"><div class=\"rbs-img-thumbs\" data-thumbnail=\"https://familylifecrc.org/wp-content/uploads/2023/01/cssj3-217x300.jpg\" title=\"cssj3\" data-width=\"217\" data-height=\"300\"></div><div class=\"rbs-img-data-popup\" data-popup=\"https://familylifecrc.org/wp-content/uploads/2023/01/cssj3.jpg\" title=\"\"></div><div class=\"thumbnail-overlay\"><div class=\"rbsIcons\"><i class=\"fa fa-search-plus rbsZoomIcon \"></i></div></div></div></div><div class=\"rbs-img  category10798 \"><div class=\"rbs-img-image   rbs-lightbox \"><div class=\"rbs-img-thumbs\" data-thumbnail=\"https://familylifecrc.org/wp-content/uploads/2023/01/cssj4-217x300.jpg\" title=\"cssj4\" data-width=\"217\" data-height=\"300\"></div><div class=\"rbs-img-data-popup\" data-popup=\"https://familylifecrc.org/wp-content/uploads/2023/01/cssj4.jpg\" title=\"\"></div><div class=\"thumbnail-overlay\"><div class=\"rbsIcons\"><i class=\"fa fa-search-plus rbsZoomIcon \"></i></div></div></div></div><div class=\"rbs-img  category10798 \"><div class=\"rbs-img-image   rbs-lightbox \"><div class=\"rbs-img-thumbs\" data-thumbnail=\"https://familylifecrc.org/wp-content/uploads/2023/01/cssj5-300x217.jpg\" title=\"cssj5\" data-width=\"300\" data-height=\"217\"></div><div class=\"rbs-img-data-popup\" data-popup=\"https://familylifecrc.org/wp-content/uploads/2023/01/cssj5.jpg\" title=\"\"></div><div class=\"thumbnail-overlay\"><div class=\"rbsIcons\"><i class=\"fa fa-search-plus rbsZoomIcon \"></i></div></div></div></div></div></div></div><script>var rbs_gallery_6a051c19f1e9c = {\"version\":\"5.1.4\",\"id\":10798,\"class\":\"id10798\",\"roboGalleryDelay\":1000,\"mainContainer\":\"#robo_gallery_main_block_rbs_gallery_6a051c19f1e9c\",\"loadingContainer\":\"#rbs_gallery_6a051c19f1e9c-block-loader\",\"loadingContainerObj\":\"rbs_gallery_6a051c19f1e9c-block-loader\",\"columnWidth\":\"auto\",\"columns\":3,\"resolutions\":[{\"columnWidth\":\"auto\",\"columns\":3,\"maxWidth\":960},{\"columnWidth\":\"auto\",\"columns\":2,\"maxWidth\":650},{\"columnWidth\":\"auto\",\"columns\":1,\"maxWidth\":450}],\"lightboxOptions\":{\"gallery\":{\"enabled\":true,\"tCounter\":\"%curr% of %total%\"},\"image\":{\"verticalFit\":true},\"mainClass\":\"my-mfp-slide-bottom mfp-img-mobile\"},\"overlayEffect\":\"direction-aware-fade\",\"boxesToLoadStart\":8,\"boxesToLoad\":8,\"waitUntilThumbLoads\":1,\"LoadingWord\":\"Loading...\",\"loadMoreWord\":\"Load More\",\"noMoreEntriesWord\":\"No More Entries\",\"horizontalSpaceBetweenBoxes\":15,\"verticalSpaceBetweenBoxes\":15,\"lazyLoad\":1,\"wrapContainer\":\"#robo-gallery-wrap-rbs_gallery_6a051c19f1e9c\",\"filterContainer\":\"#rbs_gallery_6a051c19f1e9cfilter\",\"loadMoreClass\":\"button-border-caution \"};</script></div>\n</div>\n</div>\n</td>\n</tr>\n<tr class=\"border-top\">\n<td>\n<h2>Planning for a Fantastic 2023</h2>\n<p class=\"p1\">FLCRC board members met on<b> December 17th</b> with a focus on strategic planning for 2023. Our 2020-2024 Strategic Plan re-affirms our commitment to the community, highlights our expansion to the <span class=\"s1\">new facility, and outlines the financial investment needs to achieve our </span>mission. To see the plan, visit <a href=\"https://familylifecrc.org/strategic-plan/\"><span class=\"s2\"><b>FamilyLifeCRC.org/strategic-plan</b></span></a>.</p>\n<p><img loading=\"lazy\" decoding=\"async\" class=\"aligncenter wp-image-10805 size-full\" src=\"https://familylifecrc.org/wp-content/uploads/2023/01/board.jpg\" alt=\"\" width=\"900\" height=\"650\" srcset=\"https://familylifecrc.org/wp-content/uploads/2023/01/board.jpg 900w, https://familylifecrc.org/wp-content/uploads/2023/01/board-300x217.jpg 300w, https://familylifecrc.org/wp-content/uploads/2023/01/board-768x555.jpg 768w, https://familylifecrc.org/wp-content/uploads/2023/01/board-750x542.jpg 750w\" sizes=\"auto, (max-width: 900px) 100vw, 900px\"></p></td>\n</tr>\n<tr class=\"border-top\">\n<td>\n<h2>FLCRC Supports Pro-Vision Academy with School Supplies</h2>\n<p class=\"p1\">On <b>December 13th</b>, FLCRC provided backpacks with school supplies to Houston-area charter school Pro-Vision Academy. The school serves grades 3-12 with the mission of inspiring hope and purpose through access to academic, economic, and social enrichment opportunities.</p>\n<p><img loading=\"lazy\" decoding=\"async\" class=\"aligncenter wp-image-10807 size-full\" src=\"https://familylifecrc.org/wp-content/uploads/2023/01/pro-vision.jpg\" alt=\"\" width=\"650\" height=\"900\" srcset=\"https://familylifecrc.org/wp-content/uploads/2023/01/pro-vision.jpg 650w, https://familylifecrc.org/wp-content/uploads/2023/01/pro-vision-217x300.jpg 217w\" sizes=\"auto, (max-width: 650px) 100vw, 650px\"></p></td>\n</tr>\n<tr class=\"border-top\">\n<td>\n<h2>2022 in Numbers</h2>\n<p><img loading=\"lazy\" decoding=\"async\" class=\"aligncenter wp-image-10820 size-full\" src=\"https://familylifecrc.org/wp-content/uploads/2023/01/2022innumbers.jpg\" alt=\"\" width=\"1200\" height=\"790\" srcset=\"https://familylifecrc.org/wp-content/uploads/2023/01/2022innumbers.jpg 1200w, https://familylifecrc.org/wp-content/uploads/2023/01/2022innumbers-300x198.jpg 300w, https://familylifecrc.org/wp-content/uploads/2023/01/2022innumbers-1024x674.jpg 1024w, https://familylifecrc.org/wp-content/uploads/2023/01/2022innumbers-768x506.jpg 768w, https://familylifecrc.org/wp-content/uploads/2023/01/2022innumbers-750x494.jpg 750w\" sizes=\"auto, (max-width: 1200px) 100vw, 1200px\"></p></td>\n</tr>\n</tbody>\n</table>\n<p><!--more--></p>\n<div class=\"clearfix\"></div>"
